// 综合评分计算
const results = [];

// 假设输入是技术分析和基本面分析的合并结果
for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  // 综合评分 = 技术面权重0.6 + 基本面权重0.4
  const technicalScore = item.technical_score || 50;
  const fundamentalScore = item.fundamental_score || 50;

  const totalScore = Math.round((technicalScore * 0.6) + (fundamentalScore * 0.4));

  // 投资建议
  let recommendation = '观望';
  let action = 'HOLD';

  if (totalScore >= 80) {
    recommendation = '强烈买入';
    action = 'BUY';
  } else if (totalScore >= 70) {
    recommendation = '买入';
    action = 'BUY';
  } else if (totalScore >= 60) {
    recommendation = '谨慎买入';
    action = 'BUY';
  } else if (totalScore >= 40) {
    recommendation = '观望';
    action = 'HOLD';
  } else {
    recommendation = '卖出';
    action = 'SELL';
  }

  results.push({
    json: {
      code: item.code,
      name: item.name || item.code,
      total_score: totalScore,
      technical_score: technicalScore,
      fundamental_score: fundamentalScore,
      recommendation: recommendation,
      action: action,
      current_price: item.current_price || 0,
      analysis_time: new Date().toISOString(),
      indicators: item.indicators || {},
      fundamental_data: item.fundamental_data || {}
    }
  });
}

return results;

